import sys
sys.path.insert(0, ''$JIRA_DIR'')
from jira_caller import jira_api

print(''=== ICT-135 이슈 조회 ==='')
try:
    # JIRA API를 통해 직접 이슈 조회
    response = jira_api.get(f''/rest/api/3/issue/ICT-135'')
    if response.status_code == 200:
        issue = response.json()
        fields = issue.get(''fields'', {})

        print(f''제목: {fields.get(""summary"", ""N/A"")}'')
        print(f''이슈 타입: {fields.get(""issuetype"", {}).get(""name"", ""N/A"")}'')
        print(f''상태: {fields.get(""status"", {}).get(""name"", ""N/A"")}'')
        print(f''우선순위: {fields.get(""priority"", {}).get(""name"", ""N/A"")}'')
        print()

        # 설명 출력
        description = fields.get(''description'', {})
        if description and ''content'' in description:
            print(''설명:'')
            for content_item in description[''content'']:
                if content_item.get(''type'') == ''paragraph'' and ''content'' in content_item:
                    for text_item in content_item[''content'']:
                        if text_item.get(''type'') == ''text'':
                            print(f''  {text_item.get(""text"", """")}'')
            print()

        # 승인 기준 출력 (customfield_10205)
        acceptance_criteria = fields.get(''customfield_10205'')
        if acceptance_criteria and isinstance(acceptance_criteria, dict) and ''content'' in acceptance_criteria:
            print(''승인 기준:'')
            for content_item in acceptance_criteria[''content'']:
                if content_item.get(''type'') == ''paragraph'' and ''content'' in content_item:
                    for text_item in content_item[''content'']:
                        if text_item.get(''type'') == ''text'':
                            print(f''  {text_item.get(""text"", """")}'')
            print()
    else:
        print(f''이슈 조회 실패: {response.status_code} - {response.text}'')

except Exception as e:
    print(f''오류 발생: {str(e)}'')
")
